#include <vector>

std::vector<double> multiply_vectors(const std::vector<double>& a, const std::vector<double>& b) {
    std::vector<double> result;
    result.reserve(a.size());
    for(size_t i = 0; i < a.size(); ++i) {
        result.push_back(a[i] * b[i]);
    }
    return result;
}

#include <vector>
#include <algorithm>

std::vector<double> filter_positive(const std::vector<double>& input) {
    std::vector<double> out;
    for(double val : input) {
        if(val > 0.0) out.push_back(val);
    }
    return out;
}
